public static ArrayList<Node> topological_ordering(List<Node> directedGraph) {
    ArrayList<Node> orderedNodes = new ArrayList<Node>();
    Map<Node, Integer> inDegree = new HashMap<>();

    // Compute in-degrees of all nodes
    for (Node node : directedGraph) {
        inDegree.put(node, 0);
    }
    for (Node node : directedGraph) {
        for (Node successor : node.getSuccessors()) {
            inDegree.put(successor, inDegree.get(successor) + 1);
        }
    }

    // Add nodes with in-degree 0 to the ordered list initially
    Queue<Node> queue = new LinkedList<>();
    for (Node node : inDegree.keySet()) {
        if (inDegree.get(node) == 0) {
            queue.add(node);
        }
    }

    // Process nodes in the queue and update in-degrees
    while (!queue.isEmpty()) {
        Node node = queue.poll();
        orderedNodes.add(node);
        for (Node successor : node.getSuccessors()) {
            inDegree.put(successor, inDegree.get(successor) - 1);
            if (inDegree.get(successor) == 0) {
                queue.add(successor);
            }
        }
    }

    // Check if the graph has a cycle (i.e., not all nodes are processed)
    if (orderedNodes.size() != directedGraph.size()) {
        throw new IllegalArgumentException("The graph contains a cycle, topological ordering is not possible.");
    }

    return orderedNodes;
}

